private javax.security.auth.callback.CallbackHandler loadHandlerClass(IConfigurationElement element) {
    if (!this.expectedElement(element, org.eclipse.equinox.internal.security.auth.ext.loader.ExtCallbackHandlerLoader.ELEM_HANDLER)) {
        return null;
    }
    try {
        return ((javax.security.auth.callback.CallbackHandler) (element.createExecutableExtension(org.eclipse.equinox.internal.security.auth.ext.loader.ExtCallbackHandlerLoader.ATTR_HANDLER_CLASS)));
    } catch (CoreException e) {
        java.lang.String message = org.eclipse.osgi.util.NLS.bind(org.eclipse.equinox.internal.security.auth.nls.SecAuthMessages.instantiationFailed1, element.getAttribute(org.eclipse.equinox.internal.security.auth.ext.loader.ExtCallbackHandlerLoader.ATTR_HANDLER_CLASS));
