}

public CryptoData(java.lang.String data) throws org.eclipse.equinox.security.storage.StorageException {
    super();
    // separate moduleID
    int pos = data.indexOf(org.eclipse.equinox.internal.security.storage.CryptoData.MODULE_ID_SEPARATOR);
    java.lang.String encrypted;
    if (pos == (-1)) {
        // invalid data format
        throw new org.eclipse.equinox.security.storage.StorageException(org.eclipse.equinox.security.storage.StorageException.DECRYPTION_ERROR, org.eclipse.equinox.internal.security.auth.nls.SecAuthMessages.invalidEntryFormat);
    } else if (pos == 0) {
        this.moduleID = null;
        encrypted = data.substring(1);
    } else {
        this.moduleID = data.substring(0, pos);
        encrypted = data.substring(pos + 1);
    }
    // separate salt and data
    int saltPos = encrypted.indexOf(org.eclipse.equinox.internal.security.storage.CryptoData.SALT_SEPARATOR);
    if (saltPos != (-1)) {
        this.salt = org.eclipse.equinox.internal.security.storage.Base64.decode(encrypted.substring(0, saltPos));
        this.encryptedData = org.eclipse.equinox.internal.security.storage.Base64.decode(encrypted.substring(saltPos + 1));
    } else {
        // this is a "null" value
        // double check that this is not a broken entry
        if (encrypted.length() != 0) {
            throw new org.eclipse.equinox.security.storage.StorageException(org.eclipse.equinox.security.storage.StorageException.DECRYPTION_ERROR, org.eclipse.equinox.internal.security.auth.nls.SecAuthMessages.invalidEntryFormat);
        }
        this.salt = null;
        this.encryptedData = null;
    }
}

