public javax.security.auth.login.Configuration[] getConfigurations() {
    IExtensionRegistry registry = RegistryFactory.getRegistry();
    IExtensionPoint point = registry.getExtensionPoint(org.eclipse.equinox.internal.security.auth.ConfigurationFactory.POINT_PROVIDER);
    IExtension[] extensions = point.getExtensions();
    java.util.ArrayList<javax.security.auth.login.Configuration> returnValue = new java.util.ArrayList<javax.security.auth.login.Configuration>(extensions.length);
    for (int i = 0; i < extensions.length; i++) {
        IConfigurationElement[] elements = extensions[i].getConfigurationElements();
        for (int j = 0; j < elements.length; j++) {
            javax.security.auth.login.Configuration provider = this.readProvider(elements[j]);
