    return returnValue.toArray(new javax.security.auth.login.Configuration[]{  });
}

public static java.lang.String encode(byte[] bytes) {
    if (bytes == null) {
        return null;
    }
    char[] longResult = new char[(bytes.length * 2) + 2];
    int pos = 0;
    for (int i = 0; i < bytes.length; i += 3) {
        int byte1 = 0xff & bytes[i];
        int byte2 = ((i + 1) < bytes.length) ? 0xff & bytes[i + 1] : 0;
        int byte3 = ((i + 2) < bytes.length) ? 0xff & bytes[i + 2] : 0;
        int group1 = byte1 >> 2;
        int group2 = ((byte1 & 0x3) << 4) | (byte2 >> 4);
        int group3 = ((byte2 & 0xf) << 2) | (byte3 >> 6);
        int group4 = byte3 & 0x3f;
        longResult[pos++] = org.eclipse.equinox.internal.security.storage.Base64.encodeTable[group1];
        longResult[pos++] = org.eclipse.equinox.internal.security.storage.Base64.encodeTable[group2];
        longResult[pos++] = ((i + 1) < bytes.length) ? org.eclipse.equinox.internal.security.storage.Base64.encodeTable[group3] : '=';
        longResult[pos++] = ((i + 2) < bytes.length) ? org.eclipse.equinox.internal.security.storage.Base64.encodeTable[group4] : '=';
    }
    char[] result = new char[pos];
    java.lang.System.arraycopy(longResult, 0, result, 0, pos);
    return new java.lang.String(result);
}

