public void flush(java.util.Properties properties, java.lang.String parentsPath) {
    java.lang.String thisNodePath;
    if (this.name == null) {
        thisNodePath = null;
    } else if (parentsPath == null) {
        thisNodePath = org.eclipse.equinox.internal.security.storage.SecurePreferences.PATH_SEPARATOR + this.name;
    } else {
        thisNodePath = (parentsPath + org.eclipse.equinox.internal.security.storage.SecurePreferences.PATH_SEPARATOR) + this.name;
    }
    if (this.values != null) {
        for (java.util.Map.Entry<java.lang.String, java.lang.String> entry : this.values.entrySet()) {
            java.lang.String key = entry.getKey();
            org.eclipse.equinox.internal.security.storage.PersistedPath extenalTag = new org.eclipse.equinox.internal.security.storage.PersistedPath(thisNodePath, key);
            properties.setProperty(extenalTag.toString(), entry.getValue());
        }
    }
    if (this.children != null) {
        for (java.util.Map.Entry<java.lang.String, org.eclipse.equinox.internal.security.storage.SecurePreferences> entry : this.children.entrySet()) {
            org.eclipse.equinox.internal.security.storage.SecurePreferences child = entry.getValue();
            child.flush(properties, thisNodePath);
        }
    }
}

