public java.util.List<org.eclipse.equinox.internal.security.storage.PasswordProviderSelector.ExtStorageModule> findAvailableModules(java.lang.String expectedID) {
    IExtensionRegistry registry = RegistryFactory.getRegistry();
    IExtensionPoint point = registry.getExtensionPoint(org.eclipse.equinox.internal.security.storage.PasswordProviderSelector.EXTENSION_POINT);
    IExtension[] extensions = point.getExtensions();
    java.util.ArrayList<org.eclipse.equinox.internal.security.storage.PasswordProviderSelector.ExtStorageModule> allAvailableModules = new java.util.ArrayList<org.eclipse.equinox.internal.security.storage.PasswordProviderSelector.ExtStorageModule>(extensions.length);
    for (int i = 0; i < extensions.length; i++) {
        java.lang.String moduleID = extensions[i].getUniqueIdentifier();
        // IDs on those extensions are mandatory; if not specified, ignore the extension
        if (moduleID == null) {
            continue;
        }
        moduleID = moduleID.toLowerCase();
        if ((expectedID != null) && (!expectedID.equals(moduleID))) {
            continue;
        }
        IConfigurationElement[] elements = extensions[i].getConfigurationElements();
        if (elements.length == 0) {
            continue;
        }
        IConfigurationElement element = elements[0];// only one module is allowed per extension

        if (!org.eclipse.equinox.internal.security.storage.PasswordProviderSelector.STORAGE_MODULE.equals(element.getName())) {
            this.reportError(org.eclipse.equinox.internal.security.auth.nls.SecAuthMessages.unexpectedConfigElement, element.getName(), element, null);
            continue;
        }
        java.lang.String attribute = element.getAttribute(org.eclipse.equinox.internal.security.storage.PasswordProviderSelector.MODULE_PRIORITY);
        int priority = -1;
        if (attribute != null) {
            priority = java.lang.Integer.parseInt(attribute);
            if (priority < 0) {
                priority = 0;
            }
            if (priority > 10) {
                priority = 10;
            }
        }
        java.lang.String name = extensions[i].getLabel();
        java.lang.String description = element.getAttribute(org.eclipse.equinox.internal.security.storage.PasswordProviderSelector.MODULE_DESCRIPTION);
        java.util.List<java.lang.String> suppliedHints = null;
        IConfigurationElement[] hints = element.getChildren(org.eclipse.equinox.internal.security.storage.PasswordProviderSelector.HINTS_NAME);
        if (hints.length != 0) {
            suppliedHints = new java.util.ArrayList<java.lang.String>(hints.length);
            for (int j = 0; j < hints.length; j++) {
                java.lang.String hint = hints[j].getAttribute(org.eclipse.equinox.internal.security.storage.PasswordProviderSelector.HINT_VALUE);
                if (hint != null) {
                    suppliedHints.add(hint);
                }
            }
        }
        java.lang.Object clazz;
        try {
            clazz = element.createExecutableExtension(org.eclipse.equinox.internal.security.storage.PasswordProviderSelector.CLASS_NAME);
            // Bug 537833 - on some systems, the password provider does not work (e.g. Linux with KDE desktop) so these
            // providers will request validation
            if ((clazz instanceof org.eclipse.equinox.internal.security.storage.provider.IValidatingPasswordProvider) && (!((org.eclipse.equinox.internal.security.storage.provider.IValidatingPasswordProvider) (clazz)).isValid())) {
                continue;
            }
        } catch (CoreException e) {
            continue;
        }
        allAvailableModules.add(new org.eclipse.equinox.internal.security.storage.PasswordProviderSelector.ExtStorageModule(moduleID, element, priority, name, description, suppliedHints));
    }
    java.util.Collections.sort(allAvailableModules, (org.eclipse.equinox.internal.security.storage.PasswordProviderSelector.ExtStorageModule o1,org.eclipse.equinox.internal.security.storage.PasswordProviderSelector.ExtStorageModule o2) -> {
        int p1 = o1.priority;
        int p2 = o2.priority;
        return p2 - p1;
    });
    return allAvailableModules;
}

private org.eclipse.equinox.internal.security.storage.PasswordExt getDefaultPassword(org.eclipse.equinox.security.storage.provider.IPreferencesContainer container) {
    if (container.hasOption(org.eclipse.equinox.security.storage.provider.IProviderHints.DEFAULT_PASSWORD)) {
        java.lang.Object passwordHint = container.getOption(org.eclipse.equinox.security.storage.provider.IProviderHints.DEFAULT_PASSWORD);
        if (passwordHint instanceof javax.crypto.spec.PBEKeySpec) {
            return new org.eclipse.equinox.internal.security.storage.PasswordExt(((javax.crypto.spec.PBEKeySpec) (passwordHint)), org.eclipse.equinox.internal.security.storage.SecurePreferences.DEFAULT_PASSWORD_ID);
        }
    }
    return null;
}

