public float getFloat(java.lang.String key, float defaultValue, org.eclipse.equinox.internal.security.storage.SecurePreferencesContainer container) throws org.eclipse.equinox.security.storage.StorageException {
    if (!this.hasKey(key)) {
        return defaultValue;
    }
    java.lang.String value = this.get(key, null, container);
    if (value == null) {
        return defaultValue;
    }
    try {
        return java.lang.Float.parseFloat(value);
    } catch (java.lang.NumberFormatException e) {
        return defaultValue;
    }
}

