// Basic put() and get()
public void put(java.lang.String key, java.lang.String value, boolean encrypt, org.eclipse.equinox.internal.security.storage.SecurePreferencesContainer container) throws org.eclipse.equinox.security.storage.StorageException {
    if (key == null) {
        throw new java.lang.NullPointerException();
    }
    this.checkRemoved();
    if ((!encrypt) || (value == null)) {
        org.eclipse.equinox.internal.security.storage.CryptoData clearValue = new org.eclipse.equinox.internal.security.storage.CryptoData(null, null, org.eclipse.equinox.internal.security.storage.StorageUtils.getBytes(value));
        this.internalPut(key, clearValue.toString());// uses Base64 to encode byte sequences

        this.markModified();
        return;
    }
    org.eclipse.equinox.internal.security.storage.PasswordExt passwordExt = this.getRoot().getPassword(null, container, true);
    if (passwordExt == null) {
        boolean storeDecrypted = (!org.eclipse.equinox.internal.security.storage.CallbacksProvider.getDefault().runningUI()) || org.eclipse.equinox.internal.security.storage.friends.InternalExchangeUtils.isJUnitApp();
        if (storeDecrypted) {
            // for JUnits and headless runs we store value as clear text and log a error
            org.eclipse.equinox.internal.security.storage.CryptoData clearValue = new org.eclipse.equinox.internal.security.storage.CryptoData(null, null, org.eclipse.equinox.internal.security.storage.StorageUtils.getBytes(value));
            this.internalPut(key, clearValue.toString());
            this.markModified();
            // Make this as visible as possible. Both print out the output and log a error
            java.lang.String msg = org.eclipse.osgi.util.NLS.bind(org.eclipse.equinox.internal.security.auth.nls.SecAuthMessages.storedClearText, key, this.absolutePath());
            java.lang.System.out.println(msg);
            org.eclipse.equinox.internal.security.auth.AuthPlugin.getDefault().logError(msg, new org.eclipse.equinox.security.storage.StorageException(org.eclipse.equinox.security.storage.StorageException.NO_PASSWORD, msg));
            return;
        }
        throw new org.eclipse.equinox.security.storage.StorageException(org.eclipse.equinox.security.storage.StorageException.NO_PASSWORD, org.eclipse.equinox.internal.security.auth.nls.SecAuthMessages.loginNoPassword);
    }
    // value must not be null at this point
    org.eclipse.equinox.internal.security.storage.CryptoData encryptedValue = this.getRoot().getCipher().encrypt(this.getRoot().getPassword(null, container, true), org.eclipse.equinox.internal.security.storage.StorageUtils.getBytes(value));
    this.internalPut(key, encryptedValue.toString());
    this.markModified();
}

