public static java.lang.String recoverPassword(java.lang.String[] answers, org.eclipse.equinox.internal.security.storage.SecurePreferencesRoot root, java.lang.String moduleID) {
    java.lang.String internalPassword = org.eclipse.equinox.internal.security.storage.PasswordManagement.mashPassword(answers);// create recovery password from answers

    org.eclipse.equinox.internal.security.storage.SecurePreferences node = org.eclipse.equinox.internal.security.storage.PasswordManagement.recoveryNode(root, moduleID);
    org.eclipse.equinox.internal.security.storage.PasswordExt internalPasswordExt = new org.eclipse.equinox.internal.security.storage.PasswordExt(new javax.crypto.spec.PBEKeySpec(internalPassword.toCharArray()), org.eclipse.equinox.internal.security.storage.PasswordManagement.RECOVERY_PSEUDO_ID);
    try {
        org.eclipse.equinox.internal.security.storage.CryptoData encryptedData = new org.eclipse.equinox.internal.security.storage.CryptoData(node.internalGet(org.eclipse.equinox.internal.security.storage.PasswordManagement.PASSWORD_RECOVERY_KEY));
        byte[] data = root.getCipher().decrypt(internalPasswordExt, encryptedData);
        return org.eclipse.equinox.internal.security.storage.StorageUtils.getString(data);
    } catch (java.lang.IllegalStateException e) {
        return null;
    } catch (javax.crypto.IllegalBlockSizeException e) {
        return null;
    } catch (javax.crypto.BadPaddingException e) {
        return null;
    } catch (org.eclipse.equinox.security.storage.StorageException e) {
        return null;
    }
}

private java.lang.String loadMappingEntry(IConfigurationElement element, java.lang.String configName) {
    if (!this.expectedElement(element, org.eclipse.equinox.internal.security.auth.ext.loader.ExtCallbackHandlerLoader.ELEM_MAPPING)) {
