    }
    if (configName.equals(element.getAttribute(org.eclipse.equinox.internal.security.auth.ext.loader.ExtCallbackHandlerLoader.ATTR_MAPPING_CONFIGNAME))) {
        return element.getAttribute(org.eclipse.equinox.internal.security.auth.ext.loader.ExtCallbackHandlerLoader.ATTR_MAPPING_CALLBACKID);
    }
    return null;
}

