private boolean verifyTestString(java.lang.String test) {
    if ((test == null) || (test.length() == 0)) {
        return false;
    }
    // backward compatibility: check if it is the original hard-coded string
    if (org.eclipse.equinox.internal.security.storage.SecurePreferencesRoot.PASSWORD_VERIFICATION_SAMPLE.equals(test)) {
        return true;
    }
    java.lang.String[] parts = test.split("\t");// $NON-NLS-1$

    if ((parts == null) || (parts.length == 0)) {
        return false;
    }
    if (parts.length != 4) {
        return false;
    }
    long num1 = -1;
    long num2 = -1;
    for (int i = 0; i < 4; i++) {
        if ((parts[i] == null) || (parts[i].length() == 0)) {
            return false;
        }
        try {
            switch (i) {
                case 0 :
                    num1 = java.lang.Long.decode(parts[i]).longValue();
                    break;
                case 1 :
                    num2 = java.lang.Long.decode(parts[i]).longValue();
                    break;
                case 2 :
                    {
                        long tmp = java.lang.Long.decode(parts[i]).longValue();
                        if (tmp != num2) {
                            return false;
                        }
                        break;
                    }
                case 3 :
                    {
                        long tmp = java.lang.Long.decode(parts[i]).longValue();
                        if (tmp != num1) {
                            return false;
                        }
                        break;
                    }
            }
        } catch (java.lang.NumberFormatException e) {
            return false;
        }
    }
    return true;
}

public static java.lang.String encode(java.lang.String str) {
    if (str == null) {
        return null;
    }
    int size = str.length();
    if (size == 0) {
        return str;
    }
    java.lang.StringBuffer processed = new java.lang.StringBuffer(size);
    int processedPos = 0;
    for (int i = 0; i < size; i++) {
        char c = str.charAt(i);
        if ((c == org.eclipse.equinox.internal.security.storage.SlashEncode.SLASH) || (c == org.eclipse.equinox.internal.security.storage.SlashEncode.BACK_SLASH)) {
            if (i > processedPos) {
                processed.append(str.substring(processedPos, i));
            }
            if (c == org.eclipse.equinox.internal.security.storage.SlashEncode.SLASH) {
                processed.append(org.eclipse.equinox.internal.security.storage.SlashEncode.ENCODED_SLASH);
            } else if (c == org.eclipse.equinox.internal.security.storage.SlashEncode.BACK_SLASH) {
                processed.append(org.eclipse.equinox.internal.security.storage.SlashEncode.ENCODED_BACK_SLASH);
            }
            processedPos = i + 1;
        }
    }
    if (processedPos == 0) {
        return str;
    }
    if (processedPos < size) {
        processed.append(str.substring(processedPos));
    }
    return new java.lang.String(processed);
}

protected void internalInitialize() throws org.eclipse.equinox.security.storage.StorageException {
    if ((this.cipherAlgorithm != null) && (this.keyFactoryAlgorithm != null)) {
        if (this.roundtrip(this.cipherAlgorithm, this.keyFactoryAlgorithm)) {
            return;
        }
        // this is a bad situation - JVM cipher no longer available. Both log and throw an exception
        java.lang.String msg = org.eclipse.osgi.util.NLS.bind(org.eclipse.equinox.internal.security.auth.nls.SecAuthMessages.noAlgorithm, this.cipherAlgorithm);
        org.eclipse.equinox.security.storage.StorageException e = new org.eclipse.equinox.security.storage.StorageException(org.eclipse.equinox.security.storage.StorageException.INTERNAL_ERROR, msg);
        org.eclipse.equinox.internal.security.auth.AuthPlugin.getDefault().logError(msg, e);
        throw e;
    }
    if ((this.cipherAlgorithm == null) || (this.keyFactoryAlgorithm == null)) {
        org.eclipse.core.runtime.preferences.IEclipsePreferences eclipseNode = ConfigurationScope.INSTANCE.getNode(org.eclipse.equinox.internal.security.auth.AuthPlugin.PI_AUTH);
        this.cipherAlgorithm = eclipseNode.get(org.eclipse.equinox.internal.security.storage.friends.IStorageConstants.CIPHER_KEY, org.eclipse.equinox.internal.security.storage.friends.IStorageConstants.DEFAULT_CIPHER);
        this.keyFactoryAlgorithm = eclipseNode.get(org.eclipse.equinox.internal.security.storage.friends.IStorageConstants.KEY_FACTORY_KEY, org.eclipse.equinox.internal.security.storage.friends.IStorageConstants.DEFAULT_KEY_FACTORY);
    }
    if (this.roundtrip(this.cipherAlgorithm, this.keyFactoryAlgorithm)) {
        return;
    }
    java.lang.String unavailableCipher = this.cipherAlgorithm;
    this.detect();
    if (this.availableCiphers.size() == 0) {
        throw new org.eclipse.equinox.security.storage.StorageException(org.eclipse.equinox.security.storage.StorageException.INTERNAL_ERROR, org.eclipse.equinox.internal.security.auth.nls.SecAuthMessages.noAlgorithms);
    }
    // use first available
    this.cipherAlgorithm = this.availableCiphers.keySet().iterator().next();
    this.keyFactoryAlgorithm = this.availableCiphers.get(this.cipherAlgorithm);
    java.lang.String msg = org.eclipse.osgi.util.NLS.bind(org.eclipse.equinox.internal.security.auth.nls.SecAuthMessages.usingAlgorithm, unavailableCipher, this.cipherAlgorithm);
    org.eclipse.equinox.internal.security.auth.AuthPlugin.getDefault().logMessage(msg);
}

