protected org.eclipse.equinox.internal.security.storage.SecurePreferences navigateToNode(java.lang.String pathName, boolean create) {
    if ((pathName == null) || (pathName.length() == 0)) {
        return this;
    }
    int pos = pathName.indexOf(IPath.SEPARATOR);
    if (pos == (-1)) {
        return this.getChild(pathName, create);
    } else // if path requested is absolute, pass it to the root without "/"
    if (pos == 0) {
        return this.getRoot().navigateToNode(pathName.substring(1), create);
    } else {
        // if path requested contains segments, isolate top segment and rest
        java.lang.String topSegment = pathName.substring(0, pos);
        java.lang.String otherSegments = pathName.substring(pos + 1);
        org.eclipse.equinox.internal.security.storage.SecurePreferences child = this.getChild(topSegment, create);
        if ((child == null) && (!create)) {
            return null;
        }
        return child.navigateToNode(otherSegments, create);
    }
}

