private java.util.Set<java.lang.String> findProviders(java.lang.String prefix) {
    java.security.Provider[] providers = java.security.Security.getProviders();
    java.util.Set<java.lang.String> algorithms = new java.util.HashSet<java.lang.String>();
    int prefixLength = prefix.length();
    for (int i = 0; i < providers.length; i++) {
        for (java.util.Iterator<java.util.Map.Entry<java.lang.Object, java.lang.Object>> j = providers[i].entrySet().iterator(); j.hasNext();) {
            java.util.Map.Entry<java.lang.Object, java.lang.Object> entry = j.next();
            java.lang.Object key = entry.getKey();
            if (key == null) {
                continue;
            }
            if (!(key instanceof java.lang.String)) {
                continue;
            }
            java.lang.String value = ((java.lang.String) (key));
            // skips properties like "[Cipher.ABC SupportedPaddings]"
            if (value.indexOf(' ') != (-1)) {
                continue;
            }
            if (value.startsWith(prefix)) {
                java.lang.String keyFactory = value.substring(prefixLength);
                algorithms.add(keyFactory);
            }
        }
    }
    return algorithms;
}

