        }
        return org.eclipse.equinox.internal.security.storage.StorageUtils.getString(data.getData());
    }
    org.eclipse.equinox.internal.security.storage.PasswordExt passwordExt = this.getRoot().getPassword(moduleID, container, false);
    if (passwordExt == null) {
        throw new org.eclipse.equinox.security.storage.StorageException(org.eclipse.equinox.security.storage.StorageException.NO_PASSWORD, org.eclipse.equinox.internal.security.auth.nls.SecAuthMessages.loginNoPassword);
    }
    try {
        byte[] clearText = this.getRoot().getCipher().decrypt(passwordExt, data);
        return org.eclipse.equinox.internal.security.storage.StorageUtils.getString(clearText);
    } catch (javax.crypto.IllegalBlockSizeException e) {
        // invalid password?
        throw new org.eclipse.equinox.security.storage.StorageException(org.eclipse.equinox.security.storage.StorageException.DECRYPTION_ERROR, e);
    } catch (javax.crypto.BadPaddingException e) {
