    org.eclipse.equinox.internal.security.storage.SecurePreferences node = org.eclipse.equinox.internal.security.storage.PasswordManagement.recoveryNode(root, moduleID);
    if (challengeResponse == null) {
        node.remove(org.eclipse.equinox.internal.security.storage.PasswordManagement.PASSWORD_RECOVERY_KEY);
        for (int i = 0; i < 2; i++) {
            java.lang.String key = org.eclipse.equinox.internal.security.storage.PasswordManagement.PASSWORD_RECOVERY_QUESTION + java.lang.Integer.toString(i + 1);
            node.remove(key);
        }
        root.markModified();
        return;
    }
    // create password from mixing and boiling answers
    java.lang.String internalPassword = org.eclipse.equinox.internal.security.storage.PasswordManagement.mashPassword(challengeResponse[1]);
    org.eclipse.equinox.internal.security.storage.PasswordExt internalPasswordExt = new org.eclipse.equinox.internal.security.storage.PasswordExt(new javax.crypto.spec.PBEKeySpec(internalPassword.toCharArray()), org.eclipse.equinox.internal.security.storage.PasswordManagement.RECOVERY_PSEUDO_ID);
    org.eclipse.equinox.internal.security.storage.PasswordExt password;
    try {
        password = root.getPassword(moduleID, container, false);
    } catch (org.eclipse.equinox.security.storage.StorageException e) {
        org.eclipse.equinox.internal.security.auth.AuthPlugin.getDefault().logError(org.eclipse.equinox.internal.security.auth.nls.SecAuthMessages.failedCreateRecovery, e);
        return;
    }
    try {
        byte[] data = org.eclipse.equinox.internal.security.storage.StorageUtils.getBytes(new java.lang.String(password.getPassword().getPassword()));
        org.eclipse.equinox.internal.security.storage.CryptoData encryptedValue = root.getCipher().encrypt(internalPasswordExt, data);
        node.internalPut(org.eclipse.equinox.internal.security.storage.PasswordManagement.PASSWORD_RECOVERY_KEY, encryptedValue.toString());
        root.markModified();
    } catch (org.eclipse.equinox.security.storage.StorageException e) {
        org.eclipse.equinox.internal.security.auth.AuthPlugin.getDefault().logError(org.eclipse.equinox.internal.security.auth.nls.SecAuthMessages.failedCreateRecovery, e);
        return;
    }
    // save questions
    for (int i = 0; i < challengeResponse[0].length; i++) {
        java.lang.String key = org.eclipse.equinox.internal.security.storage.PasswordManagement.PASSWORD_RECOVERY_QUESTION + java.lang.Integer.toString(i + 1);
        try {
            node.put(key, challengeResponse[0][i], false, ((org.eclipse.equinox.internal.security.storage.SecurePreferencesContainer) (container)));
        } catch (org.eclipse.equinox.security.storage.StorageException e) {
            // not going to happen for non-encrypted values
        }
        // already marked as modified
    }
}

