public boolean onChangePassword(org.eclipse.equinox.security.storage.provider.IPreferencesContainer container, java.lang.String moduleID) {
    // validation: must have a password module
    org.eclipse.equinox.internal.security.storage.PasswordProviderModuleExt moduleExt;
    try {
        moduleExt = org.eclipse.equinox.internal.security.storage.PasswordProviderSelector.getInstance().findStorageModule(moduleID);
    } catch (org.eclipse.equinox.security.storage.StorageException e) {
        return false;// no module -> nothing to do

    }
    // obtain new password first
    int passwordType = org.eclipse.equinox.security.storage.provider.PasswordProvider.CREATE_NEW_PASSWORD | org.eclipse.equinox.security.storage.provider.PasswordProvider.PASSWORD_CHANGE;
    javax.crypto.spec.PBEKeySpec password = moduleExt.getPassword(container, passwordType);
    if (password == null) {
        return false;
    }
    // create verification node
    java.lang.String key = moduleExt.getID();
    org.eclipse.equinox.internal.security.storage.PasswordExt passwordExt = new org.eclipse.equinox.internal.security.storage.PasswordExt(password, key);
    org.eclipse.equinox.internal.security.storage.CryptoData encryptedValue;
    try {
        java.lang.String test = this.createTestString();
        encryptedValue = this.getCipher().encrypt(passwordExt, org.eclipse.equinox.internal.security.storage.StorageUtils.getBytes(test));
    } catch (org.eclipse.equinox.security.storage.StorageException e) {
        java.lang.String msg = org.eclipse.osgi.util.NLS.bind(org.eclipse.equinox.internal.security.auth.nls.SecAuthMessages.encryptingError, key, org.eclipse.equinox.internal.security.storage.SecurePreferencesRoot.PASSWORD_VERIFICATION_NODE);
        org.eclipse.equinox.internal.security.auth.AuthPlugin.getDefault().logError(msg, e);
        return false;
    }
    org.eclipse.equinox.internal.security.storage.SecurePreferences node = this.node(org.eclipse.equinox.internal.security.storage.SecurePreferencesRoot.PASSWORD_VERIFICATION_NODE);
    node.internalPut(key, encryptedValue.toString());
    this.markModified();
    try {
        this.flush();
    } catch (java.io.IOException e) {
        java.lang.String msg = org.eclipse.osgi.util.NLS.bind(org.eclipse.equinox.internal.security.auth.nls.SecAuthMessages.encryptingError, key, org.eclipse.equinox.internal.security.storage.SecurePreferencesRoot.PASSWORD_VERIFICATION_NODE);
        org.eclipse.equinox.internal.security.auth.AuthPlugin.getDefault().logError(msg, e);
        return false;
    }
    // store password in the memory cache
    this.cachePassword(key, passwordExt);
    org.eclipse.equinox.internal.security.storage.CallbacksProvider.getDefault().setupChallengeResponse(key, container);
    return true;
}

