private static java.lang.String mashPassword(java.lang.String[] answers) {
    // form a string composing answers
    java.lang.StringBuffer tmp = new java.lang.StringBuffer();
    for (int i = 0; i < answers.length; i++) {
        tmp.append(answers[i].trim());
    }
    // mix it up
    java.lang.StringBuffer mix = new java.lang.StringBuffer();
    int pos = tmp.length() - 1;
    for (int i = 0; i <= pos; i++) {
        mix.append(tmp.charAt(i));
        if (i < pos) {
            mix.append(tmp.charAt(pos));
        }
        pos--;
    }
    // create digest
    java.lang.String internalPassword;
    try {
        // normally use digest of what was entered
        java.security.MessageDigest digest = java.security.MessageDigest.getInstance(org.eclipse.equinox.internal.security.storage.PasswordManagement.DIGEST_ALGORITHM);
        byte[] digested = digest.digest(org.eclipse.equinox.internal.security.storage.StorageUtils.getBytes(mix.toString()));
        internalPassword = org.eclipse.equinox.security.storage.EncodingUtils.encodeBase64(digested);
    } catch (java.security.NoSuchAlgorithmException e) {
        // just use the text as is; it is nicer to use digest but in this case no big deal
        java.lang.String msg = org.eclipse.osgi.util.NLS.bind(org.eclipse.equinox.internal.security.auth.nls.SecAuthMessages.noDigest, org.eclipse.equinox.internal.security.storage.PasswordManagement.DIGEST_ALGORITHM);
        org.eclipse.equinox.internal.security.auth.AuthPlugin.getDefault().logMessage(msg);
        internalPassword = mix.toString();
    }
    return internalPassword;
}

