private static java.util.Map processPassword(java.util.Map options, java.lang.String arg) {
    if ((arg == null) || (arg.length() == 0)) {
        return options;
    }
    java.io.File file = new java.io.File(arg);
    if (!file.canRead()) {
        java.lang.String msg = org.eclipse.osgi.util.NLS.bind(org.eclipse.equinox.internal.security.auth.nls.SecAuthMessages.unableToReadPswdFile, arg);
        org.eclipse.equinox.internal.security.auth.AuthPlugin.getDefault().logError(msg, null);
        return options;
    }
    java.io.BufferedReader is = null;
    try {
        is = new java.io.BufferedReader(new java.io.FileReader(file));
        java.lang.StringBuffer buffer = new java.lang.StringBuffer();
        for (; ;) {
            // this eliminates new line characters but that's fine
            java.lang.String tmp = is.readLine();
            if (tmp == null) {
                break;
            }
            buffer.append(tmp);
        }
        if (buffer.length() == 0) {
            return options;
        }
        if (options == null) {
            options = new java.util.HashMap<java.lang.Object, java.lang.Object>(1);
        }
        if (!options.containsKey(org.eclipse.equinox.security.storage.provider.IProviderHints.DEFAULT_PASSWORD)) {
            options.put(org.eclipse.equinox.security.storage.provider.IProviderHints.DEFAULT_PASSWORD, new javax.crypto.spec.PBEKeySpec(buffer.toString().toCharArray()));
        }
    } catch (java.io.IOException e) {
        java.lang.String msg = org.eclipse.osgi.util.NLS.bind(org.eclipse.equinox.internal.security.auth.nls.SecAuthMessages.unableToReadPswdFile, arg);
        org.eclipse.equinox.internal.security.auth.AuthPlugin.getDefault().logError(msg, e);
    } finally {
        if (is != null) {
            try {
                is.close();
            } catch (java.io.IOException e) {
                java.lang.String msg = org.eclipse.osgi.util.NLS.bind(org.eclipse.equinox.internal.security.auth.nls.SecAuthMessages.unableToReadPswdFile, arg);
                org.eclipse.equinox.internal.security.auth.AuthPlugin.getDefault().logError(msg, e);
            }
        }
    }
    return options;
}

