public synchronized javax.security.auth.login.AppConfigurationEntry[] getAppConfigurationEntry(java.lang.String name) {
    javax.security.auth.login.AppConfigurationEntry[] returnValue = this.configCache.get(name);
    if (returnValue != null) {
        return returnValue;
    }
    // Note: adding default config provider last; extension-point based configs are queried first
    javax.security.auth.login.Configuration[] configs = this.getFederatedConfigs();
    javax.security.auth.login.Configuration[] allConfigs = configs;
    if (this.defaultConfiguration != null) {
        allConfigs = new javax.security.auth.login.Configuration[configs.length + 1];
        java.lang.System.arraycopy(configs, 0, allConfigs, 0, configs.length);
        allConfigs[configs.length] = this.defaultConfiguration;
    }
    for (int i = 0; i < allConfigs.length; i++) {
        boolean found = false;
        javax.security.auth.login.AppConfigurationEntry[] config = allConfigs[i].getAppConfigurationEntry(name);
        if (config == null) {
            continue;
        }
        java.lang.String cachedProviderName = this.configToProviderMap.get(name);
        if ((cachedProviderName != null) && (!cachedProviderName.equals(allConfigs[i].getClass().getName()))) {
            java.lang.String message = org.eclipse.osgi.util.NLS.bind(org.eclipse.equinox.internal.security.auth.nls.SecAuthMessages.duplicateJaasConfig1, name, cachedProviderName);
            org.eclipse.equinox.internal.security.auth.AuthPlugin.getDefault().logError(message, null);
        } else if (found) {
            java.lang.String message = org.eclipse.osgi.util.NLS.bind(org.eclipse.equinox.internal.security.auth.nls.SecAuthMessages.duplicateJaasConfig2, name, cachedProviderName);
            org.eclipse.equinox.internal.security.auth.AuthPlugin.getDefault().logError(message, null);
        } else if ((config != null) && (config.length != 0)) {
            returnValue = config;
            this.configToProviderMap.put(name, allConfigs[i].getClass().getName());
            this.configCache.put(name, returnValue);
            found = true;
        }
    }
    if ((returnValue == null) || (returnValue.length == 0)) {
        java.lang.String message = org.eclipse.osgi.util.NLS.bind(org.eclipse.equinox.internal.security.auth.nls.SecAuthMessages.nonExistantJaasConfig, name);
        org.eclipse.equinox.internal.security.auth.AuthPlugin.getDefault().logError(message, null);
    }
    return returnValue;
}

