public void start() {
    if (this.running) {
        return;
    }
    // Kludge for the bug 215828 "JAAS and server-side Eclipse": for the time being configuration
    // substitution is turned off if running on a server. It is likely possible to work around
    // configuration substitution using Java 5 methods, but not Java 1.4
    org.osgi.framework.BundleContext context = org.eclipse.equinox.internal.security.auth.AuthPlugin.getDefault().getBundleContext();
    java.lang.String vmType = context.getProperty(org.eclipse.equinox.internal.security.auth.SecurePlatformInternal.VM_PROPERTY);
    if (org.eclipse.equinox.internal.security.auth.SecurePlatformInternal.SERVER_VM.equals(vmType)) {
        this.defaultConfiguration = null;
        this.running = true;
        return;
    }
    // end of kludge
    try {
        this.defaultConfiguration = javax.security.auth.login.Configuration.getConfiguration();
    } catch (java.lang.SecurityException e) {
        // could be caused by missing configuration provider URL;
        // this might be OK if default config provider is ignored
        this.defaultConfiguration = null;
    }
    javax.security.auth.login.Configuration.setConfiguration(new org.eclipse.equinox.internal.security.auth.ConfigurationFederator(this.defaultConfiguration));
    this.running = true;
}

