public static java.net.URL getDefaultLocation() throws java.io.IOException {
    java.lang.String userHome = java.lang.System.getProperty("user.home");// $NON-NLS-1$

    if (userHome != null) {
        java.io.File file = new java.io.File(userHome, org.eclipse.equinox.internal.security.storage.StorageUtils.propertiesFileName);
        // NOTE: Don't use File.toURI().toURL() as it will escape space characters and such.
        // The escaped sequence will fail later when we try to open a stream on it.
        return file.toURL();
    }
    // use install location
    java.net.URL installLocation = org.eclipse.equinox.internal.security.auth.AuthPlugin.getDefault().getConfigURL();
    if ((installLocation != null) && org.eclipse.equinox.internal.security.storage.StorageUtils.isFile(installLocation)) {
