private boolean isValid(java.lang.String path) {
    if ((path == null) || (path.length() == 0)) {
        return true;
    }
    char[] chars = path.toCharArray();
    boolean lastSlash = false;
    for (char c : chars) {
        if ((c <= 31) || (c >= 127)) {
            return false;
        }
        boolean isSlash = c == org.eclipse.core.runtime.IPath.SEPARATOR;
        if (lastSlash && isSlash) {
            return false;
        }
        lastSlash = isSlash;
    }
    return chars.length > 1 ? chars[chars.length - 1] != org.eclipse.core.runtime.IPath.SEPARATOR : true;
}

