public synchronized void flush() throws java.io.IOException {
    if (this.location == null) {
        return;
    }
    if (!this.modified) {
        return;
    }
    // check if the file has been modified since the last time it was touched
    if ((this.timestamp != 0) && (this.timestamp != this.getLastModified())) {
        org.eclipse.equinox.internal.security.storage.friends.IUICallbacks callback = org.eclipse.equinox.internal.security.storage.CallbacksProvider.getDefault().getCallback();
        if (callback != null) {
            java.lang.Boolean response = callback.ask(org.eclipse.equinox.internal.security.auth.nls.SecAuthMessages.fileModifiedMsg);
            if (response == null) {
                org.eclipse.equinox.internal.security.auth.AuthPlugin.getDefault().frameworkLogError(org.eclipse.equinox.internal.security.auth.nls.SecAuthMessages.fileModifiedNote, FrameworkLogEntry.WARNING, null);
            }// by default go ahead with save
             else if (!response.booleanValue()) {
                return;
            }// by default go ahead with save

        }
    }
    java.util.Properties properties = new java.util.Properties();
    properties.put(org.eclipse.equinox.internal.security.storage.SecurePreferencesRoot.VERSION_KEY, org.eclipse.equinox.internal.security.storage.SecurePreferencesRoot.VERSION_VALUE);
    // remember encyption algorithms
    java.lang.String cipherAlgorithm = this.cipher.getCipherAlgorithm();
    if (cipherAlgorithm != null) {
        properties.put(org.eclipse.equinox.internal.security.storage.friends.IStorageConstants.CIPHER_KEY, cipherAlgorithm);
        properties.put(org.eclipse.equinox.internal.security.storage.friends.IStorageConstants.KEY_FACTORY_KEY, this.cipher.getKeyFactoryAlgorithm());
    }
    // save all user properties
    this.flush(properties, null);
    // output
    java.io.OutputStream stream = null;
    try {
        stream = org.eclipse.equinox.internal.security.storage.StorageUtils.getOutputStream(this.location);
        properties.store(stream, org.eclipse.equinox.internal.security.storage.SecurePreferencesRoot.description);
        this.modified = false;
    } finally {
        if (stream != null) {
            stream.close();
        }
    }
    this.timestamp = this.getLastModified();
}

