private void init() throws org.eclipse.equinox.security.storage.StorageException {
    if (this.initialized) {
        return;
    }
    this.initialized = true;
    try {
        org.eclipse.equinox.internal.security.storage.JavaEncryption.lock.acquire();// avoid multiple simultaneous initializations

        org.eclipse.equinox.internal.security.storage.friends.IUICallbacks callback = org.eclipse.equinox.internal.security.storage.CallbacksProvider.getDefault().getCallback();
        if (callback == null) {
            this.internalInitialize();
        } else {
            callback.execute(() -> this.internalInitialize());
        }
    } finally {
        org.eclipse.equinox.internal.security.storage.JavaEncryption.lock.release();
    }
}

