public static byte[] decode(java.lang.String str) {
    if (str == null) {
        return null;
    }
    // eliminate all unexpected characters (might have EOLs inserted)
    char[] source = str.toCharArray();
    int originalSize = source.length;
    char[] tmp = new char[originalSize];
    int count = 0;
    for (int i = 0; i < originalSize; i++) {
        if (org.eclipse.equinox.internal.security.storage.Base64.decode(source[i]) != org.eclipse.equinox.internal.security.storage.Base64.BASE64_INVALID) {
            tmp[count++] = source[i];
        }
    }
    char[] chars = new char[count];
    java.lang.System.arraycopy(tmp, 0, chars, 0, count);
    int size = chars.length;
    byte[] result = new byte[size];
    int pos = 0;
    for (int i = 0; i < size; i += 4) {
        byte group1 = org.eclipse.equinox.internal.security.storage.Base64.decode(chars[i]);
        byte group2 = ((i + 1) < size) ? org.eclipse.equinox.internal.security.storage.Base64.decode(chars[i + 1]) : 0;
        byte group3 = ((i + 2) < size) ? org.eclipse.equinox.internal.security.storage.Base64.decode(chars[i + 2]) : 0;
        byte group4 = ((i + 3) < size) ? org.eclipse.equinox.internal.security.storage.Base64.decode(chars[i + 3]) : 0;
        result[pos++] = ((byte) ((group1 << 2) | (group2 >> 4)));
        if (group3 != org.eclipse.equinox.internal.security.storage.Base64.BASE64_PADDING) {
            result[pos++] = ((byte) (((group2 & 0xf) << 4) | (group3 >> 2)));
        }
        if (group4 != org.eclipse.equinox.internal.security.storage.Base64.BASE64_PADDING) {
            result[pos++] = ((byte) (((group3 & 0x3) << 6) | group4));
        }
    }
    byte[] output = new byte[pos];
    java.lang.System.arraycopy(result, 0, output, 0, pos);
    return output;
}

public java.util.HashMap<java.lang.String, java.lang.String> internalDetect() {
    java.util.Set<java.lang.String> ciphers = this.findProviders(org.eclipse.equinox.internal.security.storage.JavaEncryption.CIPHER);
    java.util.Set<java.lang.String> keyFactories = this.findProviders(org.eclipse.equinox.internal.security.storage.JavaEncryption.SECRET_KEY_FACTORY);
    this.availableCiphers = new java.util.HashMap<java.lang.String, java.lang.String>(ciphers.size());
    for (java.lang.String cipher : ciphers) {
        // check if there is a key factory with the same name
        if (keyFactories.contains(cipher)) {
            if (this.roundtrip(cipher, cipher)) {
                this.availableCiphers.put(cipher, cipher);
                continue;
            }
        }
        for (java.lang.String keyFactory : keyFactories) {
            if (this.roundtrip(cipher, keyFactory)) {
                this.availableCiphers.put(cipher, keyFactory);
                continue;
            }
        }
    }
