}

public static java.lang.String decode(java.lang.String str) {
    if (str == null) {
        return null;
    }
    int size = str.length();
    if (size == 0) {
        return str;
    }
    java.lang.StringBuffer processed = new java.lang.StringBuffer(size);
    int processedPos = 0;
    for (int i = 0; i < size; i++) {
        char c = str.charAt(i);
        if (c == org.eclipse.equinox.internal.security.storage.SlashEncode.BACK_SLASH) {
            if ((i + 2) >= size) {
                continue;
            }
            java.lang.String encoded = str.substring(i, i + 3);
            char decoded = 0;
            if (org.eclipse.equinox.internal.security.storage.SlashEncode.ENCODED_SLASH.equals(encoded)) {
                decoded = org.eclipse.equinox.internal.security.storage.SlashEncode.SLASH;
            } else if (org.eclipse.equinox.internal.security.storage.SlashEncode.ENCODED_BACK_SLASH.equals(encoded)) {
                decoded = org.eclipse.equinox.internal.security.storage.SlashEncode.BACK_SLASH;
            }
            if (decoded == 0) {
                continue;
            }
            if (i > processedPos) {
                processed.append(str.substring(processedPos, i));
            }
            processed.append(decoded);
            processedPos = i + 3;
            i += 2;// skip over remaining encoded portion

        }
    }
    if (processedPos == 0) {
        return str;
    }
    if (processedPos < size) {
        processed.append(str.substring(processedPos));
    }
    return new java.lang.String(processed);
}

public javax.security.auth.callback.CallbackHandler loadCallbackHandler(java.lang.String configName) {
    IExtensionRegistry registry = RegistryFactory.getRegistry();
    // First, map config name -> callback handler ID
    IExtensionPoint point = registry.getExtensionPoint(org.eclipse.equinox.internal.security.auth.ext.loader.ExtCallbackHandlerLoader.POINT_MAPPING);
    IExtension[] extenders = point.getExtensions();
    java.lang.String extensionId = null;
    for (int i = 0; i < extenders.length; i++) {
        IConfigurationElement[] confEelements = extenders[i].getConfigurationElements();
        if (confEelements.length != 1) {
            continue;
        }// TBD error message?

        extensionId = this.loadMappingEntry(confEelements[0], configName);
        if (extensionId != null) {
            break;
        }
    }
    if (extensionId == null) {
        return null;
    }
    // Next, load class specified by the callback handler ID
    IExtensionPoint pointCallbackHandler = registry.getExtensionPoint(org.eclipse.equinox.internal.security.auth.ext.loader.ExtCallbackHandlerLoader.POINT_HANDLER);
    IExtension extension = pointCallbackHandler.getExtension(extensionId);
    if (extension == null) {
        return null;
    }
    IConfigurationElement[] elements = extension.getConfigurationElements();
    if (elements.length != 1) {
        return null;
    }// TBD error message?

    return this.loadHandlerClass(elements[0]);
}

