public boolean isEncrypted(java.lang.String key) throws org.eclipse.equinox.security.storage.StorageException {
    this.checkRemoved();
    if (!this.hasKey(key)) {
        return false;
    }
    java.lang.String encryptedValue = this.internalGet(key);
    if (encryptedValue == null) {
        return false;
    }
    org.eclipse.equinox.internal.security.storage.CryptoData data = new org.eclipse.equinox.internal.security.storage.CryptoData(encryptedValue);
    java.lang.String moduleID = data.getModuleID();
    return moduleID != null;
}

